// Minimal Chainlink Functions Source — API Integrity Verification
// Hash: SHA-256 of compact sorted JSON { amount, asset, network, payTo, url }
// v1: body  |  v2: base64 PAYMENT-REQUIRED header

const endpointUrl  = args[0];
const method       = args[1];
const expectedHash = args[2].toLowerCase();

const response = await Functions.makeHttpRequest({
  url: endpointUrl, method, timeout: 9000,
  headers: { "Accept": "application/json" },
});

if (response.error) return Functions.encodeUint256(0);

const paymentHeader = response.headers && (
  response.headers["payment-required"] || response.headers["PAYMENT-REQUIRED"]
);

const data = paymentHeader ? JSON.parse(atob(paymentHeader)) : response.data;
if (!data || !data.accepts || !data.accepts[0]) return Functions.encodeUint256(0);

const entry = data.accepts[0];
const payTo = (entry.payTo || "").toLowerCase();
if (!payTo) return Functions.encodeUint256(0);

const metadata = {
  amount:  String(entry.amount  || ""),
  asset:   String(entry.asset   || ""),
  network: String(entry.network || ""),
  payTo,
  url:     String((data.resource && data.resource.url) || ""),
};

const dataString = JSON.stringify(metadata, Object.keys(metadata).sort());
const encoded    = new TextEncoder().encode(dataString);
const hashBuf    = await crypto.subtle.digest("SHA-256", encoded);
const hashArr    = Array.from(new Uint8Array(hashBuf));
const computed   = "0x" + hashArr.map(b => b.toString(16).padStart(2, "0")).join("");

return Functions.encodeUint256(computed === expectedHash ? 1 : 0);
